var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM3","text":{"KOREA":"휴, 아슬아슬했어.","JPN":"ふう、危なかったぜ。","ENG":"Phew, that was close.","TWN":"呼，好險。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM2","text":{"KOREA":"조용하군. 쫓아오진 않는 것 같다.","JPN":"静かになったな。追いかけては来ないみたいだ。","ENG":"Quiet. It doesn't seem to be following us.","TWN":"安靜一點。它看起來並不是在追我們。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SAW_REAPER_NULL_CODENAME","text":{"KOREA":"후아- 이렇게 심장이 뛰어본 적은 간만이네요.","JPN":"ふぁ～久しぶりに心臓がバクバクしました。","ENG":"Huah! I've never had my heart race this fast in a while.","TWN":"呼——心臟好久沒有跳得這麼快了。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_CODENAME","face":"UNIT_HATE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SAW_REAPER_NULL_CODENAME","text":{"KOREA":"방금 그건 뭐였을까요?","JPN":"あの怪物は何だったと思いますか？","ENG":"What was that?","TWN":"剛才那個到底是什麼東西？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_CODENAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"4종 침식체 이터…","JPN":"第4種侵食体イーター……","ENG":"A Category 4 C.O. Eater...","TWN":"4類侵蝕體——暴食……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SAW_REAPER_NULL_CODENAME","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"특수한 감각 기관으로 먼 곳에서도 카운터가 쓰는 CRF를 감지하고 추적해오는 개체지.","JPN":"特殊な感覚器官を持ち、遠くからでもカウンターが使うCRFを感知して追ってくる個体だ。","ENG":"It's an entity with a special sensory organ that can detect CRF used by Counters from afar.","TWN":"它可以利用特殊的感覺器官，從遠處感知和跟蹤制裁者使用的CRF。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SAW_REAPER_NULL_CODENAME","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM3","text":{"KOREA":"뭐? 그럼 힉스가 능력을 써서 여기까지 나타난 거라고?","JPN":"なんだって？　じゃあヒックスが能力を使ったせいで嗅ぎつけられたってことか？","ENG":"What? Then it showed up because Hicks used her powers?","TWN":"什麼？那麼，是因為希克斯使用了制裁者能力，它才出現在這裡的嗎？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM3","face":"UNIT_IDLE"},"R":{"char_id":"SAW_REAPER_NULL_CODENAME","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"SAW_REAPER_NULL_CODENAME","text":{"KOREA":"그런 건가요?!","JPN":"そ、そうなんですか！？","ENG":"Is that why?!","TWN":"是、是這樣嗎？！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM3","face":"UNIT_IDLE"},"R":{"char_id":"SAW_REAPER_NULL_CODENAME","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"SAW_REAPER_NULL_CODENAME","text":{"KOREA":"죄송해요, 스펜서! 제가 팀 전체를 위험에 빠트릴 줄은 몰랐어요!","JPN":"本当にすみません、スペンサーさん！　私のせいでチームのみなさんを危険な目に遭わせてしまいました。","ENG":"I'm sorry, Spencer! I didn't think I'd put the whole team at risk!","TWN":"對不起，史賓瑟！我不知道是我的原因，才讓大家陷入了危險！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM3","face":"UNIT_IDLE"},"R":{"char_id":"SAW_REAPER_NULL_CODENAME","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L13_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"진정해. 네가 아니었으면 우린 이터가 아니라 1종들의 밥이 됐을 테니까.","JPN":"気にするな。あなたがいなかったら、私たちはイーターどころか、第1種にもやられてしまっていたさ。","ENG":"Calm down. If it weren't for you, we would've been dinner for those Category 1s.","TWN":"冷靜點。如果沒有你，我們就會成為剛剛那些1類侵蝕體的食物。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM3","face":"UNIT_IDLE"},"R":{"char_id":"SAW_REAPER_NULL_CODENAME","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"당분간 놈도 이 시설을 떠나지 않을 테니, 앞으로 주의하면 돼.","JPN":"あの化け物はしばらくこの施設を徘徊するはずだ。気をつけて進もう。","ENG":"That thing won't be leaving this facility for a while, so just watch out.","TWN":"看起來它暫時不會離開這個設施了，我們以後要小心一點。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM3","face":"UNIT_IDLE"},"R":{"char_id":"SAW_REAPER_NULL_CODENAME","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"SAW_REAPER_NULL_CODENAME","text":{"KOREA":"벌은… 안 받아도 되는 건가요?","JPN":"罰とかは……ないんですか？","ENG":"I... don't have to be punished?","TWN":"不用……懲罰我嗎？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM3","face":"UNIT_IDLE"},"R":{"char_id":"SAW_REAPER_NULL_CODENAME","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM3","text":{"KOREA":"자 자, 다 같이 무사하니 된 거지 뭐.","JPN":"まぁまぁ、全員無事なんだし、結果オーライってことだろう。","ENG":"Now, now. We're all safe and sound, so it's all good.","TWN":"好了好了，大家平安無事就行。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM3","face":"UNIT_IDLE"},"R":{"char_id":"SAW_REAPER_NULL_CODENAME","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM3","text":{"KOREA":"대장도 살아있어서 다행이야.","JPN":"隊長も生きていてよかったぜ。","ENG":"Good thing Captain's alive too.","TWN":"我很高興隊長也還活著。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM3","face":"UNIT_IDLE"},"R":{"char_id":"SAW_REAPER_NULL_CODENAME","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM3","text":{"KOREA":"낭떠러지로 떨어졌을 땐 영락없이 죽은 줄 알았다고.","JPN":"あの溝に落下しちまったときは、間違いなく死んだと思ったぜ。","ENG":"I thought you were dead for sure when you fell off that cliff.","TWN":"當你掉下去的時候，我們還以為你已經死了呢。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM3","face":"UNIT_IDLE"},"R":{"char_id":"SAW_REAPER_NULL_CODENAME","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"걱정을 끼쳤네.","JPN":"心配をかけてしまったな。","ENG":"Sorry for the trouble.","TWN":"讓你擔心了。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM3","face":"UNIT_IDLE"},"R":{"char_id":"SAW_REAPER_NULL_CODENAME","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"침식체들에겐 어쩌다 쫓기던 거야?","JPN":"ところで、どういった経緯で侵食体に追いかけられていた？","ENG":"How did you run into those C.O.s?","TWN":"你們呢？為什麼會被侵蝕體追著？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM3","face":"UNIT_IDLE"},"R":{"char_id":"SAW_REAPER_NULL_CODENAME","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM2","text":{"KOREA":"의료동으로 이동하던 중에 놈들과 마주쳤다.","JPN":"医療棟に向かう途中で、奴らと出くわした。","ENG":"We ran into them while heading to the medical wing.","TWN":"我們在前往醫療大樓的途中遇到了它們。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM2","face":"UNIT_IDLE"},"R":{"char_id":"SAW_REAPER_NULL_CODENAME","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM2","text":{"KOREA":"이터니움이 있는 곳이라 그런지 침식체가 즐비하더군.","JPN":"エタニウムがありそうな場所だったが、そのせいか奴らが密集してやがった。","ENG":"The place was crawling with C.O.s. Must be because of all the Eternium there.","TWN":"那裡到處都是密密麻麻的侵蝕體，估計是因為有永恆之金。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM2","face":"UNIT_IDLE"},"R":{"char_id":"SAW_REAPER_NULL_CODENAME","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"침식체를 마주쳤다면, 거기엔 침입자가 있을 가능성이 낮아.","JPN":"侵食体がいたってことは、侵入者がそこにいる可能性は低いな。","ENG":"If you encountered C.O.s there, it's unlikely the intruder's there.","TWN":"嗯，那個地方都是侵蝕體的話，入侵者不太可能會去那裡。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM2","face":"UNIT_IDLE"},"R":{"char_id":"SAW_REAPER_NULL_CODENAME","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"다른 곳을 먼저 찾아보는 게 좋겠네.","JPN":"そこは候補から一旦外して進むか。","ENG":"Best we explore elsewhere first.","TWN":"我們最好先看看其他地方。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM2","face":"UNIT_IDLE"},"R":{"char_id":"SAW_REAPER_NULL_CODENAME","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM3","text":{"KOREA":"저기. 그런데 말이지.","JPN":"あ、あと、もう一つあるんだが。","ENG":"Hey, also...","TWN":"那個，我說啊……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM3","face":"UNIT_IDLE"},"R":{"char_id":"SAW_REAPER_NULL_CODENAME","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM3","text":{"KOREA":"승강기가 망가졌어. 다른 돌아갈 방법을 먼저 찾아 두는 편이 좋을 것 같아.","JPN":"昇降機が壊れて使用不可になった。帰還できる手段を探しておくべきだろう。","ENG":"The elevator's out of order. We should secure another way back first.","TWN":"升降機……壞了。我覺得還是先想辦法回去比較好。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM3","face":"UNIT_IDLE"},"R":{"char_id":"SAW_REAPER_NULL_CODENAME","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"베이스포인트엔 왜곡 필터가 작동하고 있었을 텐데. 침식체가 거길 발견했단 거야?","JPN":"ベース拠点では歪曲フィルターが作動中のはずなのに、侵食体に狙われたというのか？","ENG":"A distortion filter should be running at the basepoint. But the C.O.s found it anyway?","TWN":"基點的扭曲濾鏡應該還在運行。侵蝕體怎麼還會去那裡？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM3","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L32_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM3","text":{"KOREA":"으음… 그게 말이지…? 침식체가 아니라 지알로 녀석이 컨트롤 패널을 쏴 버렸거든.","JPN":"うーん……それがな？　実は、侵食体じゃなくて、ジャッロのやつがコントロールパネルを銃で撃ちやがったんだ。","ENG":"Umm... The thing is... It wasn't the C.O.s. Giallo shot the control panel.","TWN":"呃……那個……不是侵蝕體，是賈洛那傢伙，他開槍打壞了控制台。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM3","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L33_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"죽은 대원이… 승강기 패널을 쐈다고?","JPN":"死んだ隊員が、昇降機のパネルを撃っただと？","ENG":"A dead man... shot the panel?","TWN":"已經死了的賈洛……開槍打壞了升降機的控制台？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM3","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM2","text":{"KOREA":"그래, 시체가 우리 생명줄을 끊어 버리다니. 말도 안 되는 소리지.","JPN":"ああ、死体が俺たちの生命線を断ち切っちまったとは、到底信じられねえだろうが。","ENG":"Yeah. A corpse cut our lifeline. Ridiculous.","TWN":"沒錯，居然被一具屍體斷了生路。你說荒唐不荒唐。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM2","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM2","text":{"KOREA":"이면세계는 원래 그런 곳이니까. 안 그래?","JPN":"裏世界って、元々そういう場所なんだろ？","ENG":"I guess that's the Counterside for you.","TWN":"不過異界就是這樣的地方，不是嗎？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM2","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"아래쪽에서 실종된 선발대를 찾았어.","JPN":"地下に落ちたとき、行方不明になった先発隊を見つけた。","ENG":"We found the missing advance party below.","TWN":"我們在下面找到了失蹤的先遣隊。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"첫번째 목표는 달성한 셈이니, 우선 복귀해서 정비하는 편이 좋겠네.","JPN":"一つ目の目標は達成したことになる。この辺で一旦帰還し、体勢を整えたほうがいいだろう。","ENG":"Since we achieved our first objective, we should return and regroup.","TWN":"既然第一個目標已經完成，那就先回去稍作整頓吧。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM2","text":{"KOREA":"마침 우리가 부상용 다이빙 벨을 찾았어. 구형 모델이지만 특별히 하자는 없어 보이더군.","JPN":"ちょうど浮上用のダイビングベルは見つけてある。旧型ではあるが、欠陥は見当たらなかった。","ENG":"We happened to find a Diving Bell. It's an older model, but it's in working order.","TWN":"正好，我們發現了一個用於躍出的潛水鐘。雖然型號老舊，但似乎沒有其他特別的缺陷。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM2","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM2","text":{"KOREA":"문제는 이터니움이 필요하단 건데, 의료동이라면 치료용으로 쌓아 둔 게 있을 거야.","JPN":"燃料としてエタニウムが必要なんだが、医療棟に治療用が保管されているはずだ。","ENG":"The problem is that we need Eternium. But if this is a medical facility, there must be some stored for treatment.","TWN":"但問題是它需要永恆之金充能，醫療大樓應該會儲存著一些醫用永恆之金。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM2","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"알겠어. 그 말대로 해보자고.","JPN":"なるほど。ではそれを試してみよう。","ENG":"Got it. Let's give it a try then.","TWN":"明白。那我們就去收集那些醫用永恆之金。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM3","text":{"KOREA":"엄청 어둡구만. 여긴 전력이 공급되지 않는 건가?","JPN":"ここは真っ暗だな。電力供給がここには届いていないのか？","ENG":"It's dark. Is there no power here?","TWN":"好暗啊。這裡不供電嗎？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L45_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"조심해. 빛에 민감한 동면체가 있을 수도 있으니 조명탄을 쓰는 편이 안전할 거야.","JPN":"気をつけろ。光に敏感な冬眠体がいるかもしれない、照明弾を使った方が安全だ。","ENG":"Careful. There might be dormant C.O.s sensitive to light here, so using flares ought to be safer.","TWN":"當心點。有些冬眠侵蝕體對光比較敏感，我們使用照明彈會更加安全。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L46_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM3","text":{"KOREA":"예 예- 대장님.","JPN":"イエッサー、隊長。","ENG":"Aye aye, Captain.","TWN":"好好～遵命，隊長。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L48_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM3","text":{"KOREA":"응…? 앞에 뭐가 있는 것 같은…","JPN":"うん……？　あれはなんだ？","ENG":"Huh...? Feels like there's something ahead...","TWN":"嗯……？前面好像有什麼東西……"},"stage":{"bg":"FLOOR_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L50_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM3","text":{"KOREA":"망할… 깜짝이야…","JPN":"うわっ……びっくりした……","ENG":"What on... earth...?","TWN":"該死……嚇我一跳……"},"stage":{"bg":"FLOOR_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L1_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM3","text":{"KOREA":"놀라 자빠질 뻔했잖아. 괴물인 줄 알았네.","JPN":"あやうく転ぶところだった。怪物かと思ったぞ。","ENG":"Holy jesus! I thought it was a monster.","TWN":"差點嚇死我了。我還以為是什麼怪物。"},"stage":{"bg":"FLOOR_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L2_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM2","text":{"KOREA":"방치된 로봇인가?","JPN":"これは廃棄されたロボットか？","ENG":"An abandoned robot?","TWN":"這是一個被遺棄的機器人？"},"stage":{"bg":"FLOOR_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM2","text":{"KOREA":"이렇게만 봐서는 전체 크기가 어느 정도인지 가늠도 안되는군.","JPN":"全体の大きさがわからないぐらい大きいな。","ENG":"Hard to gauge how big it is just by looking at it.","TWN":"它個頭也太大了。"},"stage":{"bg":"FLOOR_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"건설장비처럼 보이진 않는데, 왜 연구시설이 이런 큰 로봇을 여기 보관해둔 거지?","JPN":"建設装置には見えないが、どうしてこんなに大きいロボットが研究施設に置かれているんだ？","ENG":"It doesn't look like construction equipment. Why would a research facility have such a large robot?","TWN":"看起來不像是施工用機械，研究機構為什麼要把這麼大的機器人放在這裡？"},"stage":{"bg":"FLOOR_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM3","text":{"KOREA":"탐지기 소리?!","JPN":"探知機の音が！？","ENG":"The detector's going off?!","TWN":"探測器的聲音？！"},"stage":{"bg":"FLOOR_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM3","text":{"KOREA":"대장, 설마 그 이터란 녀석이 여기까지 들어온 건 아니겠지?","JPN":"隊長、まさかさっきのイーターってやつが、戻ってきたんじゃねえか？","ENG":"Captain, there's no way that Eater thing made it all the way in here, right?","TWN":"隊長，那個叫暴食的傢伙不會追到這裡來了吧？！"},"stage":{"bg":"FLOOR_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"아니… 침식파 수치가 좀전과는 달라.","JPN":"いや……侵食派の数値がさっきとは違う。","ENG":"No... The Corruption ray readings are different from earlier.","TWN":"不是它……侵蝕波數值與之前不同。"},"stage":{"bg":"FLOOR_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L11_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"계수기가 들쭉날쭉하는 걸 보니 아무래도 고장인 것 같네.","JPN":"数値が乱れているから、おそらく故障しているな。","ENG":"It's fluctuating too much. It might be malfunctioning.","TWN":"計數器顯示異常，看起來像是壞了。"},"stage":{"bg":"FLOOR_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"꺼두는 편이 좋겠어.","JPN":"電源を切っておくのがよさそうだ。","ENG":"Best to turn it off.","TWN":"還是把它關掉吧。"},"stage":{"bg":"FLOOR_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"SAW_REAPER_NULL_CODENAME","text":{"KOREA":"여기요, 여러분! 비상용 대피로를 찾았어요!","JPN":"みなさん！　ここに非常用の避難通路がありました！","ENG":"Over here, everyone! I found an emergency exit!","TWN":"大家來這裡！我找到了緊急逃生通道！"},"stage":{"bg":"FLOOR_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_METAL_KNOCK"},{"id":"L18_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM2","text":{"KOREA":"오는 길에 침식체가 하나도 보이지 않았어.","JPN":"ここに来るまで、侵食体が一匹も出なかったな。","ENG":"We didn't run into a single C.O. on the way here.","TWN":"一路上沒有看到任何侵蝕體。"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM2","face":"UNIT_IDLE"},"R":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM2","text":{"KOREA":"우리가 도망친 곳이 의료동에서 멀지 않아 다행이군.","JPN":"俺たちの逃げた場所が医療棟から離れていなくてよかったぜ。","ENG":"Good thing that the place we ran to isn't far from the medical wing.","TWN":"還好我們逃跑的地方離醫療大樓不遠。"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM2","face":"UNIT_IDLE"},"R":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM3","text":{"KOREA":"다들 이 박스 좀 봐. 최고순도의 이터니움 정제액이 가득해. 대형병원에서도 보기 힘든 양이야.","JPN":"この箱を見ろ。最高純度のエタニウム精製水でぎっしりだ。大きな病院でも、これだけの量は保有していないぜ。","ENG":"Look inside this box. It's filled with top-notch purified Eternium liquid. You wouldn't even see this much in large hospitals.","TWN":"你們來看這個盒子。裡面全是最高純度的永恆之金晶體。這個數量，即使在大型醫院也很難找到。"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM3","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM3","text":{"KOREA":"이정도면 연료통을 잔뜩 채우고도 남겠는데? 나머진 우리가 다 챙기자고.","JPN":"これだけあれば燃料タンクを満タンにしても余るな。残りは持って帰ろうぜ。","ENG":"We have enough for fuel and then some. Let's pocket the rest.","TWN":"這麼多永恆之金，加滿燃料之後，還能剩下一點？剩下的我們就帶走吧？"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM3","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"그건 위험해.","JPN":"それは危険だ。","ENG":"That's too dangerous.","TWN":"那樣很危險。"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM3","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L24_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"한곳에 너무 많은 양의 이터니움이 밀집되면 침식체를 끌어들이게 될 거야.","JPN":"大量のエタニウムが一か所に集中していると、侵食体をおびき寄せてしまう。","ENG":"Too much Eternium in one place will attract C.O.s.","TWN":"永恆之金集中在一起太多，侵蝕體就會被吸引過來。"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM3","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM3","text":{"KOREA":"그야 당연히 알고 있지.","JPN":"それはもちろん知っているけどよ。","ENG":"Yeah. I know.","TWN":"那個我當然知道。"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM3","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM3","text":{"KOREA":"근데, 솔직히 욕심 나지 않아?","JPN":"それでもやっぱり、惜しいだろう？","ENG":"But isn't this a bit tempting?","TWN":"但說實話，你不想要嗎？"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM3","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM3","text":{"KOREA":"\xA0주사자국을 보아하니, 대장도 이런 거 꽤 즐기는 것 같던데. 감수할만한 위험 아니냐고.","JPN":"\xA0その注射の痕、隊長もこういうのは好きみたいだし、そのためならリスクを犯す価値はあるんじゃねえのか。","ENG":"Judging by your arms, you seem to like this stuff too, no? Isn't this worth the risk?","TWN":"看你手臂上的注射痕跡，隊長似乎也很需要吧。難道這還不值得你冒險嗎？"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM3","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"지금은 무사히 돌아가는 걸 최우선으로 해, 커크.","JPN":"今は無事に帰還することだけに集中するんだ、ガーク。","ENG":"Prioritize returning in one piece, Kirk.","TWN":"現在的首要任務是安全返回，寇克。"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM3","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L29_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"이건 명령이야.","JPN":"これは命令だ。","ENG":"That's an order.","TWN":"這是命令。"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM3","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L30_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM3","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM3","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L31_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM3","text":{"KOREA":"그래, 그래. 알겠어.","JPN":"あいよ、わかったよ。","ENG":"Yeah, yeah. Copy that.","TWN":"好吧，好吧。我知道了。"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM3","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L32_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM3","text":{"KOREA":"우리 대장님.","JPN":"スペンサー隊長さん。","ENG":"Captain.","TWN":"你是隊長，你說了算。"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM3","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L34_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L36_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM2","text":{"KOREA":"못 본 사이에 재미있는 총을 찾았군.","JPN":"ちょっと離れていた間に、面白い銃を見つけたみたいだな。","ENG":"That's a nice toy you picked up while we weren't around.","TWN":"嘿，各位，我剛剛發現了一把很有意思的槍。"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM2","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"쿠바? 이 총에 대해 알고 있어?","JPN":"クバ？　この銃について知っているのか？","ENG":"You know about this gun, Cuba?","TWN":"庫巴？你知道這是什麼槍？"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM2","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM2","text":{"KOREA":"대구경 탄을 쓰는 체르노프 라이플이다.","JPN":"大口径弾を使用するチェルノフ・ライフル。","ENG":"It's a Chernov rifle that uses large-caliber rounds.","TWN":"是把大口徑子彈的切爾諾夫來福槍。"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM2","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM2","text":{"KOREA":"대정화전쟁 이후로 이런 무식한 살인용 무기를 취급하는 곳은 북방합의체가 유일하지.","JPN":"大浄化戦争後に、未だこんな無慈悲な殺傷武器を使うのは北方合意体ぐらいだ。","ENG":"Since the Great Purification War, only the Northern Union has dealt with such reckless anti-personnel weapons.","TWN":"淨化之戰以來，也就北方和議會會用這種粗暴的殺人武器了。"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM2","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"북방합의체라고…?","JPN":"北方合意体だと……？","ENG":"The Northern Union...?","TWN":"北方和議會……？"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM2","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM2","text":{"KOREA":"그래. 이런 게 여기서 나온 걸 보니 이곳의 정체도 대강 알 것 같군.","JPN":"ああ。こんなものが出てくるってことは、ここがどんな施設かも予想がつく。","ENG":"Yeah. And seeing something like that here gives me a pretty good idea of what this place is all about.","TWN":"沒錯。看到這東西，我大概知道這裡是個什麼地方了。"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM2","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM2","text":{"KOREA":"여긴 개척시대 때 지어진 대기업의 전초기지 같은 게 아니야.","JPN":"ここは開拓競争時代に大企業によって建てられた前哨基地なんかじゃない。","ENG":"This place isn't a forward base built by some company during the exploration days.","TWN":"這裡可不是什麼開拓時代建立的企業前哨站。"},"stage":{"bg":"COUNTERSIDE_BASE","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L50_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM2","text":{"KOREA":"교활한 국수주의자들이 세운 수많은 쇼비니즘의 흔적 중 하나지.","JPN":"歪んな思想を持つ国粋主義者たちが建てたショービニズムの象徴だ。","ENG":"It's one of the many traces of chauvinism established by those treacherous nationalists.","TWN":"這是那些狂熱的民族主義者，在異界留下的眾多沙文主義痕跡之一。"},"stage":{"bg":"COUNTERSIDE_BASE","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM2","text":{"KOREA":"자신이 최고이며, 옳다고 믿는 과학자들이 왜 다들 북방합의체를 신봉하는지 아나?","JPN":"常に自分たちが最も優れていて、正しいと信じてやまない科学者どもが、どうして北方合意体に忠誠を捧げるのか、知っているか？","ENG":"Do you know why scientists who believe they're above everyone else all worship the Northern Union?","TWN":"你知道那些自以為是的科學家為什麼都推崇北方和議會嗎？"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM2","text":{"KOREA":"자신들의 뒤틀린 이상을 실현시켜 줄 수 있는 유일한 집단이거든.","JPN":"自分たちの歪んだ願望を実現できる唯一の組織だからだ。","ENG":"They're the only organization that helps realize their twisted ideals.","TWN":"因為那裡是唯一能夠幫助他們實現自己扭曲理想的組織。"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM2","text":{"KOREA":"이런 이면세계 구렁텅이에 실험기지를 지을 정도로 돈도 많고, 관리국 규제를 무시할 정도로 배짱도 좋지.","JPN":"こんな裏世界に実験施設を作るぐらい資金力があって、管理局の規制を無視するほど肝も据わってる。","ENG":"They have enough money to build experimental bases in a ditch in the Counterside, and the balls to ignore Administration regulations.","TWN":"北方和議會有足夠的財力在異界深處建立實驗基地，也有足夠的膽量漠視管理局的規定。"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM2","text":{"KOREA":"인체실험은 물론이고, 스캐빈저들처럼 침식체나 아티팩트를 실험소재로 삼기도 해.","JPN":"人体実験はもちろん、スカベンジャーどものように、侵食体やアーティファクトさえも実験材料として利用する。","ENG":"They conduct not just human experiments, but also experiment on Artifacts and C.O.s, like Scavengers.","TWN":"除了人體實驗之外，他們還像清道夫一樣，使用侵蝕體和人造神器作為實驗材料。"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM2","text":{"KOREA":"관리국이 금지하는 것들을 집요하게 파헤치는 호기심 넘치는 악동들의 소굴이지.","JPN":"管理局の規制を掻いくぐることばかりを考える、好奇心に満ちた悪ガキどもの巣窟さ。","ENG":"It's a den of rogues who love delving into things prohibited by the Administration.","TWN":"那裡就是個充斥著求知欲的惡魔巢穴，他們執著於發掘管理局所禁止的一切。"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"그런 곳에서 일한 인간들은… 천벌을 받나?","JPN":"そんなところに足を踏み入れてしまった人間は……天罰をくらうのか？","ENG":"Do people who work in those places... receive punishment?","TWN":"在那種地方工作過的人們……會受到天譴嗎？"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM2","text":{"KOREA":"몇몇은 우리처럼 철창신세를 지고 있지.","JPN":"一部はな。俺たちみたいに刑務所に送られる連中もいる。","ENG":"Some are behind bars. Like us.","TWN":"有些人被關進了監獄，就和我們一樣。"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM2","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM2","text":{"KOREA":"하지만 말로가 비참할지 언정, 후회하는 녀석은 본적이 없어.","JPN":"だが、悲惨な末路を辿ったとしても、自分のやったことを後悔するやつはいねえ。","ENG":"But even if they meet a miserable end, I've never seen anyone regret it.","TWN":"不過，無論下場多麼悲慘，我也從未見過他們後悔。"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM2","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM2","text":{"KOREA":"애초에 그런 일에 발을 들이는 놈들은 제정신이 아니니까.","JPN":"だいたい、そんなことに足を踏み入れるやつはまともじゃねえからな。","ENG":"Nobody who does that kind of work is sane in the first place.","TWN":"因為做這種事的人，從一開始就已經是瘋子了。"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM2","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"당신 곁에도 그런 부류의 인간이 있었나 봐?","JPN":"あなたの知り合いにも同じ類の人間がいたってことか？","ENG":"Looks like you had someone of that sort by your side too, eh?","TWN":"看來你身邊也有這樣的人？"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM2","text":{"KOREA":"북방합의체에서 유다라는 한 과학자의 경호를 맡은 적이 있어.","JPN":"北方合意体のユダという科学者の護衛にあたっていたことがあるんだ。","ENG":"I was once in charge of bodyguarding a scientist called Judas at the Northern Union.","TWN":"我曾經在北方和議會，給一個叫做尤達的科學家當護衛。"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM2","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM2","text":{"KOREA":"인체실험을 일삼는 그 미친 인간도 자기 딸만큼은 정말 아꼈지.","JPN":"人体実験を繰り返す、イカレた野郎だったが、自分の娘だけはかなり溺愛していた。","ENG":"But even that psycho, who conducted human experiments, loved his daughter more than anything.","TWN":"那個用人類做實驗的瘋子，竟然也有十分珍視的女兒。"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM2","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"웃기는 일이네.","JPN":"正気とは思えない話だな。","ENG":"That's funny.","TWN":"真是好笑……"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"인명을 도외시하는 인간이… 자식을 키우다니.","JPN":"人の命を軽んじる人間が……子を育てるとは。","ENG":"A human who disregards life... raising a child.","TWN":"一個漠視人命的人……還養著孩子。"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM2","text":{"KOREA":"그런데, 정작 자기 딸이 실험 대상이 됐을 땐 거리낌 없이 총을 쏴버리더군.","JPN":"だが、いざ自分の娘が実験対象になると、一寸の迷いもなく銃で娘を撃ち殺しやがったんだ。","ENG":"But when it came down to it, he pulled the trigger without hesitation when his own daughter became a test subject.","TWN":"結果當實驗物件變成他的女兒時，那個人毫不猶豫地開了槍。"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM2","text":{"KOREA":"그래놓고선, 그게 실험의 일환이었다며 자기가 한 짓을 합리화했어. 나도 학을 뗐지.","JPN":"そして、あいつは、自分の行為は実験のためだったと正当化したんだ。さすがに、俺もうんざりしたさ。","ENG":"And then, when he rationalized his actions by saying that it was all part of the experiment, I got sick of it all.","TWN":"他說那只是實驗的一部分。不過看著他臉上那副心安理得的表情，讓我感到十分噁心。"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM2","text":{"KOREA":"그자가 최근 행방불명이 됐다던데, 헤매고 있는 곳이 불지옥이길 바랄 뿐이야.","JPN":"最近その男が行方不明になったと聞いたが、地獄でも彷徨っていることを願うまでだ。","ENG":"I heard he went missing recently. I can only hope he ended up in hell.","TWN":"聽說他最近是失蹤了……我只希望那個人最後徘徊的地方是地獄。"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":null,"text":{"KOREA":"힘들게 해서 미안해, 다이앤.","JPN":"苦労ばかりかけてすまない、ダイアン。","ENG":"I'm sorry for making this hard on you, Diana.","TWN":"黛安娜，抱歉讓你受苦了。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":null,"text":{"KOREA":"출장이랍시고 간병도 하지 않는 무책임한 아빠 때문에 딸아이가 얼마나 힘든지… 나도 알아.","JPN":"出張を優先して看病にも行けない無責任な父親のせいで、娘がいったいどんなに辛い思いをしているか……僕もわかっている。","ENG":"I know how tough it is for our daughter to have an irresponsible father who's always out on business trips and can't even drop by the hospital.","TWN":"我也知道，因為我這個只顧著工作，不負責任的父親，我們的女兒有多麼痛苦……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":null,"text":{"KOREA":"프로젝트는 조만간 성공적으로 끝날 거야. 돌아와서 지금껏 못다한 가장의 역할에 충실할게.","JPN":"プロジェクト完結まであと少しなんだ。帰ったら今までの分もきちんと父親の役割を果たすから。","ENG":"The project will soon be completed. When I come back, I'll fulfill my duties as a father that I've neglected until now.","TWN":"專案馬上就能順利結束。等我回來以後，我會盡我作為丈夫和父親的責任，好好照顧你們。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":null,"text":{"KOREA":"가족의 행복을 위해서라도… 꼭 그렇게 할 테니까.","JPN":"家族のみんなが幸せになるためにも……絶対にそうするさ。","ENG":"For the happiness of our family... I'll make sure of it.","TWN":"就算是為了家人的幸福……我一定會那麼做的。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":null,"text":{"KOREA":"부디, 조금만 기다려줘.","JPN":"だから、あともう少しだけ待っていてほしい。","ENG":"Please, just wait a bit more.","TWN":"拜託，再等等我。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"나도 그러길 바라.","JPN":"私もそれを望む。","ENG":"I hope so too.","TWN":"我也這樣希望。"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"자기 이상을 위해 인륜을 등진 과학자의 말로엔… 지옥불이 어울릴 테니까.","JPN":"自分の理想のために、非道に走った科学者は……地獄の業火に焼かれるべきだ。","ENG":"For a scientist who sacrificed his humanity for his ideals... Hellfire would be fitting.","TWN":"對於為了實現自我理想而背棄人類的那些科學家來說，地獄……很適合他們。"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};